function b64url(buf) {
  return buf
    .toString('base64')
    .replace(/\+/g, '-')
    .replace(/\//g, '_')
    .replace(/=+$/g, '');
}

function randomToken(bytes = 32) {
  return b64url(crypto.randomBytes(bytes));
}

function sha256Base64Url(input) {
  return b64url(crypto.createHash('sha256').update(input).digest());
}

function nowSec() {
  return Math.floor(Date.now() / 1000);
}

