  if (!client) return res.status(400).send('invalid_client');
  if (!client.allowed_grants.has('authorization_code')) return res.status(400).send('unauthorized_client');
  if (!validateRedirectUri(client, redirect_uri)) return res.status(400).send('invalid_redirect_uri');

