// ---- Introspection (simple) ----
// POST /introspect token=...
app.post('/introspect', requireClientAuth, async (req, res) => {
  const client = req.oauth.client;
  const token = String(req.body.token || '');
  if (!token) return res.status(400).json({ error: 'invalid_request' });

  // If it's our signed access token, extract payload
  const parts = token.split('.');
  if (parts.length !== 3) return res.json({ active: false });

  let payload;
  try {
    payload = JSON.parse(Buffer.from(parts[1].replace(/-/g, '+').replace(/_/g, '/'), 'base64').toString('utf8'));
  } catch {
    return res.json({ active: false });
  }

  if (!payload || payload.typ !== 'access_token' || !payload.jti) return res.json({ active: false });
  if (payload.aud !== client.client_id) return res.json({ active: false });

  const at = await getAccessTokenByJti(String(payload.jti));
  if (!at) return res.json({ active: false });

  const t = nowSec();
  if (at.exp && t >= at.exp) return res.json({ active: false });

  return res.json({
    active: true,
    iss: payload.iss,
    sub: at.user_id,
    aud: at.client_id,
    scope: (at.scope || []).join(' '),
    exp: at.exp,
    iat: at.iat,
    token_type: 'Bearer',
  });
});

